const {execSync}=require('child_process');
try {
  const out=execSync('diff -qr .claude/skills .agents/skills || true', {encoding:'utf8'});
  const lines=out.split('\n').filter(Boolean).filter(l=>!l.includes('gsap-'));
  console.log(lines.length ? lines.join('\n') : 'Non-GSAP skills match between .claude/skills and .agents/skills.');
} catch(e){ console.log('verification failed:', e.message); }

