					<div className={s.column}>{stats.slice(3).map((item) => <StatCard key={item.label} {...item} />)}</div>
				</div>
			</div>
		</section>
	);
}

function StatCard({ text, value, label, dark, kind, tall }: {
	text?: string;
	value?: string;
	label: string;
	dark?: boolean;
	kind?: string;
	tall?: boolean;
}) {
	return (
