content.text:
import s from "./ImpactFeatures.module.css";

const stats = [
	{
		kind: "avatars",
		label: "Trust user world wide",
	},
	{
		text: "Our platform helps you stay focused, meet deadlines, and achieve more every single day.",
		value: "10,000+",
		label: "Active users managing their daily work with ease",
	},
	{
		dark: true,
		text: "Every task completed, every deadline met—our numbers reflect real progress made by real people like you.",
		value: "4.9/5",
		label: "Average user rating",
	},
	{
		text: "Our platform is built to deliver measurable results. From improved efficiency to stronger team collaboration, our impact is reflected in the numbers.",
		value: "99.9%",
		label: "Uptime for reliable performance",
	},
	{
		kind: "timer",
		label: "3x Faster Project completion time",
	},
];

export default function ImpactFeatures() {
	return (
		<section id="impacts" className={s.section}>
			<div className={s.container}>
				<header className={s.header}>
					<div className={s.headingGroup}>
						<span className={s.badge}>Our impacts</span>
						<h2>
							Real Results. <br />
							Real Impact.
						</h2>
					</div>
					<p>
						See how thousands of users are transforming the way they work. From
						faster project completion to less stress, our platform helps you
						achieve more—every single day.
					</p>
				</header>

				<div className={s.grid}>
					<div className={s.column}>
						{stats.slice(0, 2).map((item) => (
							<StatCard key={item.label} {...item} />
						))}
					</div>
					<StatCard {...stats[2]} tall />
					<div className={s.column}>
						{stats.slice(3).map((item) => (
							<StatCard key={item.label} {...item} />
						))}
					</div>
				</div>
			</div>
		</section>
	);
}

function StatCard({
	text,
	value,
	label,
	dark,
	kind,
	tall,
}: {
	text?: string;
	value?: string;
	label: string;
	dark?: boolean;
	kind?: string;
	tall?: boolean;
}) {
	return (
		<article
			className={`${s.card} ${dark ? s.dark : ""} ${tall ? s.tall : ""}`}
		>
			{kind === "avatars" ? (
				<div className={s.avatarRow} aria-hidden="true">
					<span />
					<span />
					<span />
					<b>♕</b>
				</div>
			) : null}
			{kind === "timer" ? (
				<div className={s.timerRow}>
					<span aria-hidden="true">⏱</span>
					<strong>{label}</strong>
				</div>
			) : null}
			{text ? <p className={s.cardText}>{text}</p> : null}
			{value ? (
				<div className={s.metric}>
					<strong>{value}</strong>
					{dark ? (
						<span aria-hidden="true" className={s.stars}>
							★★★★★
						</span>
					) : null}
					<span>{label}</span>
				</div>
			) : null}
			{kind === "avatars" ? (
				<span className={s.smallLabel}>{label}</span>
			) : null}
		</article>
	);
}

