content.text:
import s from "./HowItWorks.module.css";

const steps = [
	{
		step: "Step 1",
		title: "Download Appo",
		description: "Appo is available on App Store and Play Store.",
		featured: true,
	},
	{
		step: "Step 2",
		title: "Set up your account",
		description: "Easily create your profile and start adding tasks.",
	},
	{
		step: "Step 3",
		title: "Get to work",
		description: "Organize your tasks, track progress, and achieve more.",
	},
];

export default function HowItWorks() {
	return (
		<section id="how-it-works" className={s.section}>
			<div className={s.header}>
				<span className={s.badge}>How it works</span>
				<h2>Get started in 3 simple steps.</h2>
				<p>Explore the features designed to keep you organized and on track.</p>
			</div>

			<div className={s.steps}>
				{steps.map((step) => (
					<article
						className={`${s.stepCard} ${step.featured ? s.featured : ""}`}
						key={step.step}
					>
						<div className={s.stepCopy}>
							<span className={s.stepBadge}>{step.step}</span>
							<div>
								<h3>{step.title}</h3>
								<p>{step.description}</p>
							</div>
						</div>
						{step.featured ? (
							<div className={s.phoneStage} aria-hidden="true">
								<PhoneMockup />
								<span className={s.storeA}>App Store</span>
								<span className={s.storeB}>Google Play</span>
							</div>
						) : null}
					</article>
				))}
			</div>
		</section>
	);
}

function PhoneMockup() {
	return (
		<div className={s.phone}>
			<div className={s.speaker} />
			<div className={s.phoneHeader} />
			{["Plan sprint", "Design review", "Ship update"].map((item) => (
				<span key={item}>{item}</span>
			))}
		</div>
	);
}

import s from "./FeatureShowcase.module.css";

const featureCards = [
	{
		title: "Smart Task Organization",
		description:
			"Create, prioritize, and categorize tasks with ease. Use tags, due dates, and custom lists to stay on top of everything.",
		visual: "stack",
	},
	{
		title: "Deadline Reminders",
		description:
			"Never miss important due dates with gentle reminders and a clear view of what needs your attention next.",
		visual: "calendar",
	},
	{
		title: "Progress Tracking",
		description:
			"See exactly how your work is moving forward with simple progress states and visual task summaries.",
		visual: "progress",
	},
	{
		title: "Team Collaboration",
		description:
			"Assign tasks, leave comments, share files, and track progress in real-time—no more endless back-and-forth.",
		visual: "team",
	},
];

export default function FeatureShowcase() {
	return (
		<section
			id="features"
			className={s.section}
			data-section="features"
			data-pencil-id="zVQYG"
			data-pencil-name="Features"
		>
			<div className={s.container}>
				<header className={s.header}>
					<span className={s.badge}>Our features</span>
					<h2>Features designed for your success.</h2>
					<p>
						Explore the features designed to keep you organized and on track.
					</p>
				</header>

				<div
					className={s.cards}
					data-pencil-id="Uqtay"
					data-pencil-name="Features"
				>
					{featureCards.map((card, index) => (
						<article
							className={s.card}
							key={card.title}
							data-pencil-name="Feature Card"
						>
							<div className={s.visual} aria-hidden="true">
								<Visual type={card.visual} />
							</div>
							<div className={s.copy}>
								<span className={s.icon}>{index + 1}</span>
								<h3>{card.title}</h3>
								<p>{card.description}</p>
							</div>
						</article>
					))}
				</div>
			</div>
		</section>
	);
}

function Visual({ type }: { type: string }) {
	if (type === "calendar") {
		const days = [
			"mon",
			"tue",
			"wed",
			"thu",
			"fri",
			"sat",
			"sun",
			"next-mon",
			"next-tue",
			"next-wed",
			"next-thu",
			"next-fri",
		];
		return (
			<div className={s.calendar}>
				{days.map((day, i) => (
					<span key={day} className={i === 5 || i === 9 ? s.active : ""} />
				))}
			</div>
		);
	}
	if (type === "progress") {
		return (
			<div className={s.progressBox}>
				<b>82%</b>
				<span />
				<span />
				<span />
			</div>
		);
	}
	if (type === "team") {
		return (
			<div className={s.teamBox}>
				<span />
				<span />
				<span />
				<b>+8</b>
			</div>
		);
	}
	return (
		<div className={s.stack}>
			{["Research", "Wireframe", "Launch"].map((item) => (
				<span key={item}>{item}</span>
			))}
		</div>
	);
}

