							pin: true,
							scrub: 0.6,
							invalidateOnRefresh: true,
						},
					});

					return () => tween.kill();
				},
			);

			return () => mm.revert();
		},
		{ scope: sectionRef },
	);

	return (
		<section
			ref={sectionRef}
			id="features"
			className={s.section}
			data-section="features"
			data-pencil-id="zVQYG"
			data-pencil-name="Features"
		>
			<div className={s.container}>
				<header className={s.header}>
					<span className={s.badge}>Our features</span>
					<h2>Features designed for your success.</h2>
					<p>
						Explore the features designed to keep you organized and on track.
					</p>
				</header>

				<div className={s.viewport}>
					<div
						ref={trackRef}
						className={s.cards}
						data-pencil-id="Uqtay"
						data-pencil-name="Features"
					>
						{featureCards.map((card, index) => (
							<article
								className={s.card}
								key={card.title}
								data-pencil-name="Feature Card"
