"use client";

import { useGSAP } from "@gsap/react";
import gsap from "gsap";
import { useRef, useState } from "react";
import s from "./FeatureShowcase.module.css";

gsap.registerPlugin(useGSAP);

const featureCards = [
	{
		title: "Smart Task Organization",
		description:
			"Create, prioritize, and categorize tasks with ease. Use tags, due dates, and custom lists to stay on top of everything.",
		visual: "stack",
	},
	{
		title: "Deadline Reminders",
		description:
			"Never miss important due dates with gentle reminders and a clear view of what needs your attention next.",
		visual: "calendar",
	},
	{
		title: "Progress Tracking",
		description:
			"See exactly how your work is moving forward with simple progress states and visual task summaries.",
		visual: "progress",
	},
	{
		title: "Team Collaboration",
		description:
			"Assign tasks, leave comments, share files, and track progress in real-time—no more endless back-and-forth.",
		visual: "team",
	},
];

export default function FeatureShowcase() {
	const sectionRef = useRef<HTMLElement>(null);
	const cardRef = useRef<HTMLDivElement>(null);
	const [activeIndex, setActiveIndex] = useState(0);
	const activeFeature = featureCards[activeIndex];

	useGSAP(
		() => {
			const card = cardRef.current;
			if (!card) return;

			gsap.fromTo(
				card,
				{ autoAlpha: 0, y: 18, scale: 0.985 },
				{ autoAlpha: 1, y: 0, scale: 1, duration: 0.45, ease: "power3.out" },
			);
		},
		{ scope: sectionRef, dependencies: [activeIndex], revertOnUpdate: true },
	);

	const goToPrevious = () => {
		setActiveIndex((current) =>
			(current - 1 + featureCards.length) % featureCards.length,
		);
	};

	const goToNext = () => {
		setActiveIndex((current) => (current + 1) % featureCards.length);
	};

	return (
		<section
			ref={sectionRef}
			id="features"
			className={s.section}
			data-section="features"
			data-pencil-id="zVQYG"
			data-pencil-name="Features"
		>
			<div className={s.container}>
				<header className={s.header}>
					<span className={s.badge}>Our features</span>
					<h2>Features designed for your success.</h2>
					<p>
						Explore the features designed to keep you organized and on track.
					</p>
				</header>

				<div className={s.carousel} data-pencil-id="Uqtay" data-pencil-name="Features">
					<div ref={cardRef} className={s.cardShell}>
						<article className={s.card} data-pencil-name="Feature Card">
							<div className={s.visual} aria-hidden="true">
								<Visual type={activeFeature.visual} />
							</div>
							<div className={s.copy}>
								<span className={s.icon}>{activeIndex + 1}</span>
								<h3>{activeFeature.title}</h3>
								<p>{activeFeature.description}</p>
							</div>
						</article>
					</div>

					<div className={s.controls}>
						<button type="button" onClick={goToPrevious} aria-label="Show previous feature">←</button>
						<div className={s.dots} aria-label="Feature carousel pagination">
							{featureCards.map((card, index) => (
								<button
									type="button"
									key={card.title}
									className={index === activeIndex ? s.activeDot : ""}
									onClick={() => setActiveIndex(index)}
									aria-label={`Show ${card.title}`}
								/>
							))}
						</div>
						<button type="button" onClick={goToNext} aria-label="Show next feature">→</button>
					</div>
				</div>
			</div>
		</section>
	);
}

function Visual({ type }: { type: string }) {
	if (type === "calendar") {
		const days = [
			"mon",
			"tue",
			"wed",
			"thu",
			"fri",
			"sat",
			"sun",
			"next-mon",
			"next-tue",
			"next-wed",
			"next-thu",
			"next-fri",
		];
		return (
			<div className={s.calendar}>
				{days.map((day, i) => (
					<span key={day} className={i === 5 || i === 9 ? s.active : ""} />
				))}
			</div>
		);
	}
	if (type === "progress") {
		return (
			<div className={s.progressBox}>
				<b>82%</b>
				<span />
				<span />
				<span />
			</div>
		);
	}
	if (type === "team") {
		return (
			<div className={s.teamBox}>
				<span />
				<span />
				<span />
				<b>+8</b>
			</div>
		);
	}
	return (
		<div className={s.stack}>
			{["Research", "Wireframe", "Launch"].map((item) => (
				<span key={item}>{item}</span>
			))}
		</div>
	);
}

.section {
	background: #f7f7f7;
	padding: 80px 52px;
	overflow: hidden;
}

.container {
	max-width: 1176px;
	margin-inline: auto;
	display: flex;
	flex-direction: column;
	gap: 64px;
}

.header {
	display: flex;
	flex-direction: column;
	align-items: center;
	gap: 16px;
	text-align: center;
}

.badge {
	display: inline-flex;
	align-items: center;
	justify-content: center;
	height: 28px;
	padding: 0 16px;
	border-radius: 28px;
	background: #fff;
	font-size: 12px;
	letter-spacing: 1.44px;
	line-height: 1.333;
	color: #131313;
}

.header h2 {
	max-width: 576px;
	font-size: 64px;
	font-weight: 500;
	line-height: 1.125;
	letter-spacing: -2.56px;
	color: #262424;
}

.header p {
	max-width: 375px;
	font-size: 16px;
	line-height: 1.5;
	color: #505050;
}

.carousel {
	display: flex;
	flex-direction: column;
	gap: 24px;
}

.cardShell {
	min-height: 448px;
}

.card {
	display: grid;
	grid-template-columns: minmax(0, 1fr) minmax(320px, 0.72fr);
	gap: 24px;
	min-height: 448px;
	padding: 16px;
	border-radius: 24px;
	background: #fff;
}

.visual {
	position: relative;
	overflow: hidden;
	min-height: 416px;
	border-radius: 8px;
	background: #f7f7f7;
	display: grid;
	place-items: center;
}

.copy {
	display: flex;
	flex-direction: column;
	justify-content: center;
	gap: 12px;
	padding: 24px;
}

.icon {
	width: 48px;
	height: 48px;
	border-radius: 12px;
	background: #a0f4d8;
	display: grid;
	place-items: center;
	font-size: 16px;
	font-weight: 500;
	color: #262424;
}

.copy h3 {
	font-size: 32px;
	font-weight: 500;
	line-height: 1.25;
	letter-spacing: -1.28px;
	color: #262424;
}

.copy p {
	font-size: 16px;
	line-height: 1.5;
	color: #505050;
}

.controls {
	display: flex;
	align-items: center;
	justify-content: center;
	gap: 18px;
}

.controls button {
	border: none;
	cursor: pointer;
}

.controls > button {
	width: 44px;
	height: 44px;
	border-radius: 14px;
	background: #262424;
	color: #fff;
	font-size: 18px;
}

.dots {
	display: flex;
	align-items: center;
	gap: 10px;
}

.dots button {
	width: 10px;
	height: 10px;
	border-radius: 999px;
	background: rgba(38, 36, 36, .2);
	transition: width .25s ease, background-color .25s ease;
}

.dots .activeDot {
	width: 32px;
	background: #262424;
}

.stack,
.progressBox {
	display: flex;
	flex-direction: column;
	gap: 16px;
	width: min(396px, 78%);
}

.stack span,
.progressBox,
.teamBox {
	border-radius: 14px;
	background: #fff;
	box-shadow: 0 24px 64px rgba(0, 0, 0, 0.08);
	padding: 18px;
}

.stack span {
	display: block;
	font-size: 16px;
	color: #262424;
}

.stack span:nth-child(2) {
	transform: translateX(32px);
}

.calendar {
	display: grid;
	grid-template-columns: repeat(4, 52px);
	gap: 12px;
	padding: 24px;
	border-radius: 16px;
	background: #fff;
	box-shadow: 0 24px 64px rgba(0, 0, 0, 0.08);
}

.calendar span {
	height: 52px;
	border-radius: 12px;
	background: #eef0f1;
}

.calendar .active {
	background: #a0f4d8;
}

.progressBox b {
	font-size: 56px;
	line-height: 1;
	color: #262424;
}

.progressBox span {
	height: 12px;
	border-radius: 99px;
	background: #e5e5e5;
}

.progressBox span:nth-child(2) { width: 92%; background: #a0f4d8; }
.progressBox span:nth-child(3) { width: 68%; }
.progressBox span:nth-child(4) { width: 78%; }

.teamBox {
	display: flex;
	align-items: center;
	gap: 0;
}

.teamBox span,
.teamBox b {
	width: 72px;
	height: 72px;
	border-radius: 50%;
	margin-left: -18px;
	border: 3px solid #fff;
	background: linear-gradient(135deg, #d0e9fb, #a0f4d8);
}

.teamBox span:first-child { margin-left: 0; }
.teamBox span:nth-child(2) { background: linear-gradient(135deg, #ede87e, #f3c6a3); }
.teamBox span:nth-child(3) { background: linear-gradient(135deg, #c8b7ff, #50a8e4); }
.teamBox b { display: grid; place-items: center; background: #262424; color: #fff; }

@media (max-width: 991px) {
	.section { padding: 64px 24px; }
	.header h2 { font-size: 48px; letter-spacing: -1.92px; }
	.card,
	.cardShell { min-height: auto; }
	.card { grid-template-columns: 1fr; }
	.visual { min-height: 280px; }
}

@media (max-width: 767px) {
	.section { padding: 48px 16px; }
	.header h2 { font-size: 40px; letter-spacing: -1.6px; }
	.copy { padding: 8px; }
	.copy h3 { font-size: 28px; }
	.controls { justify-content: space-between; }
}
